import { useState, useEffect } from 'react'

function Timer() {
  const [seconds, setSeconds] = useState(0)
  const [running, setRunning] = useState(false)

  useEffect(() => {
    if (!running) return  // Effekt nur wenn running = true

    // Interval starten — Seiteneffekt
    const id = setInterval(() => {
      setSeconds(prev => prev + 1)  // Funktionsform für aktuellen State
    }, 1000)

    // Cleanup: Interval stoppen wenn running wechselt oder Unmount
    return () => clearInterval(id)

  }, [running])  // Effekt neu ausführen wenn running sich ändert

  return (
    <div>
      <p>Zeit: {seconds}s</p>
      <button onClick={() => setRunning(r => !r)}>
        {running ? 'Stop' : 'Start'}
      </button>
      <button onClick={() => { setRunning(false); setSeconds(0) }}>
        Reset
      </button>
    </div>
  )
}

export default Timer

import { useState, useEffect } from 'react'

interface User {
  id: number
  name: string
  email: string
}

function UserFetch() {
  const [user, setUser]       = useState<User | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError]     = useState<string | null>(null)

  useEffect(() => {
    // Innere async-Funktion — sofort aufgerufen
    async function fetchUser() {
      try {
        const res = await fetch('https://jsonplaceholder.typicode.com/users/1')
        if (!res.ok) throw new Error('HTTP ' + res.status)
        const data: User = await res.json()
        setUser(data)
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Fehler')
      } finally {
        setLoading(false)  // Immer ausgeführt
      }
    }
    fetchUser()
  }, [])  // [] = nur beim Mount

  if (loading) return <p>Laden...</p>
  if (error)   return <p>Fehler: {error}</p>
  if (!user)   return null

  return (
    <div>
      <h2>{user.name}</h2>
      <p>{user.email}</p>
    </div>
  )
}

export default UserFetch

