interface FormData {
  email: string
  password: string
}

function LoginForm() {
  const [form, setForm]     = useState<FormData>({ email: '', password: '' })
  const [errors, setErrors] = useState<Partial<FormData>>({})

  // Generischer Handler — nutzt name-Attribut des Inputs
  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const { name, value } = e.target
    setForm(prev => ({ ...prev, [name]: value }))  // [name] = computed key
  }

  function validate(): boolean {
    const errs: Partial<FormData> = {}
    if (!form.email.includes('@'))  errs.email = 'Ungültige E-Mail'
    if (form.password.length < 6)   errs.password = 'Min. 6 Zeichen'
    setErrors(errs)
    return Object.keys(errs).length === 0
  }

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (validate()) console.log('Login:', form)
  }

  return (
    <form onSubmit={handleSubmit}>
      <input name="email" type="email" value={form.email} onChange={handleChange} />
      {errors.email && <span>{errors.email}</span>}

      <input name="password" type="password" value={form.password} onChange={handleChange} />
      {errors.password && <span>{errors.password}</span>}

      <button type="submit">Anmelden</button>
    </form>
  )
}

