interface CartItem { id: number; name: string; quantity: number }
interface CartState { items: CartItem[]; total: number }

// Discriminated Union — jede Aktion hat ihren Typ
type CartAction =
  | { type: 'ADD_ITEM';    payload: CartItem }
  | { type: 'REMOVE_ITEM'; payload: number }  // payload = id
  | { type: 'CLEAR' }

// Reducer: reine Funktion (currentState, action) → newState
export function cartReducer(state: CartState, action: CartAction): CartState {
  switch (action.type) {
    case 'ADD_ITEM':
      return { ...state, items: [...state.items, action.payload], total: state.total + 1 }
    case 'REMOVE_ITEM':
      return { ...state, items: state.items.filter(i => i.id !== action.payload), total: state.total - 1 }
    case 'CLEAR':
      return { items: [], total: 0 }
    default:
      return state
  }
}

export const initialCartState: CartState = { items: [], total: 0 }

import { useReducer } from 'react'
import { cartReducer, initialCartState } from './cartReducer'

function Cart() {
  const [state, dispatch] = useReducer(cartReducer, initialCartState)

  function addItem() {
    dispatch({
      type: 'ADD_ITEM',
      payload: { id: Date.now(), name: 'Artikel ' + (state.items.length + 1), quantity: 1 }
    })
  }

  return (
    <div>
      <h2>Warenkorb ({state.total})</h2>
      <button onClick={addItem}>Hinzufügen</button>
      <button onClick={() => dispatch({ type: 'CLEAR' })}>Leeren</button>
      <ul>
        {state.items.map(item => (
          <li key={item.id}>
            {item.name}
            <button onClick={() => dispatch({ type: 'REMOVE_ITEM', payload: item.id })}>✕</button>
          </li>
        ))}
      </ul>
    </div>
  )
}

export default Cart

// Generische Select-Komponente — funktioniert für beliebige Typen
interface SelectProps<T> {
  options: T[]
  getValue: (option: T) => string
  getLabel: (option: T) => string
  selected: T | null
  onChange: (value: T) => void
}

// <T,> mit Komma — sonst denkt TypeScript es ist JSX
function Select<T,>({ options, getValue, getLabel, selected, onChange }: SelectProps<T>) {
  return (
    <select
      value={selected ? getValue(selected) : ''}
      onChange={e => {
        const found = options.find(o => getValue(o) === e.target.value)
        if (found) onChange(found)
      }}
    >
      <option value="">— Auswählen —</option>
      {options.map(option => (
        <option key={getValue(option)} value={getValue(option)}>
          {getLabel(option)}
        </option>
      ))}
    </select>
  )
}

export default Select

