import type { User, LoginData, RegisterData, AuthContextType } from '../types'

const AuthContext = createContext<AuthContextType | null>(null)

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser]         = useState<User | null>(null)
  const [isLoading, setLoading] = useState(true)

  // Gespeicherten User aus localStorage laden
  useEffect(() => {
    const stored = localStorage.getItem('auth_user')
    if (stored) setUser(JSON.parse(stored))
    setLoading(false)
  }, [])

  async function register(data: RegisterData): Promise<void> {
    const newUser: User = { id: crypto.randomUUID(), username: data.username, email: data.email }
    localStorage.setItem('auth_user', JSON.stringify(newUser))
    setUser(newUser)
  }

  async function login(data: LoginData): Promise<void> {
    const stored = localStorage.getItem('auth_user')
    if (!stored) throw new Error('Kein Account gefunden — bitte registrieren')
    const savedUser: User = JSON.parse(stored)
    if (savedUser.email !== data.email) throw new Error('E-Mail stimmt nicht')
    setUser(savedUser)
  }

  function logout() {
    localStorage.removeItem('auth_user')
    setUser(null)
  }

  return (
    <AuthContext.Provider value={{ user, login, register, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth(): AuthContextType {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth muss innerhalb AuthProvider genutzt werden')
  return ctx
}

import { Navigate, Outlet } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'

function PrivateRoute() {
  const { user, isLoading } = useAuth()

  if (isLoading) return <div>Laden...</div>  // Auth-State wird geladen
  if (!user)     return <Navigate to="/login" replace />  // Nicht eingeloggt

  return <Outlet />  // Eingeloggt: Kind-Route rendern
}

export default PrivateRoute

