import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import type { LoginData } from '../types'

function LoginPage() {
  const [form, setForm]       = useState<LoginData>({ email: '', password: '' })
  const [error, setError]     = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const { login } = useAuth()
  const navigate  = useNavigate()

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setError(null)
    setLoading(true)
    try {
      await login(form)
      navigate('/dashboard')  // Nach Login zur Dashboard-Seite
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Login fehlgeschlagen')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ maxWidth: '400px', margin: '60px auto' }}>
      <h2>⚽ SportsDash Login</h2>
      <form onSubmit={handleSubmit}>
        <input name="email" type="email" value={form.email} onChange={handleChange}
               placeholder="E-Mail" required style={{ display: 'block', margin: '8px 0', width: '100%', padding: '10px' }} />
        <input name="password" type="password" value={form.password} onChange={handleChange}
               placeholder="Passwort" required style={{ display: 'block', margin: '8px 0', width: '100%', padding: '10px' }} />
        {error && <p style={{ color: 'red' }}>{error}</p>}
        <button type="submit" disabled={loading} style={{ width: '100%', padding: '10px', background: '#e94560', color: '#fff', border: 'none' }}>
          {loading ? 'Anmelden...' : 'Anmelden'}
        </button>
      </form>
      <p>Noch kein Account? <Link to="/register">Registrieren</Link></p>
    </div>
  )
}

export default LoginPage

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { useAuth } from '../context/AuthContext'
import type { RegisterData } from '../types'

function RegisterPage() {
  const [form, setForm]       = useState<RegisterData>({ username: '', email: '', password: '' })
  const [error, setError]     = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const { register } = useAuth()
  const navigate = useNavigate()

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }))
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (form.password.length < 6) { setError('Passwort min. 6 Zeichen'); return }
    setLoading(true)
    try {
      await register(form)
      navigate('/dashboard')
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Fehler')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ maxWidth: '400px', margin: '60px auto' }}>
      <h2>⚽ Registrieren</h2>
      <form onSubmit={handleSubmit}>
        <input name="username" value={form.username} onChange={handleChange}
               placeholder="Benutzername" required style={{ display: 'block', margin: '8px 0', width: '100%', padding: '10px' }} />
        <input name="email" type="email" value={form.email} onChange={handleChange}
               placeholder="E-Mail" required style={{ display: 'block', margin: '8px 0', width: '100%', padding: '10px' }} />
        <input name="password" type="password" value={form.password} onChange={handleChange}
               placeholder="Passwort (min. 6 Zeichen)" required style={{ display: 'block', margin: '8px 0', width: '100%', padding: '10px' }} />
        {error && <p style={{ color: 'red' }}>{error}</p>}
        <button type="submit" disabled={loading} style={{ width: '100%', padding: '10px', background: '#e94560', color: '#fff', border: 'none' }}>
          {loading ? 'Registrieren...' : 'Registrieren'}
        </button>
      </form>
      <p>Schon registriert? <Link to="/login">Anmelden</Link></p>
    </div>
  )
}

export default RegisterPage

