import { memo } from 'react'
import type { Match } from '../types'

const MatchCard = memo(function MatchCard({ match }: { match: Match }) {
  const { teams, goals, fixture, league } = match
  const isLive     = ['1H','2H','ET','HT'].includes(fixture.status.short)
  const isFinished = fixture.status.short === 'FT'

  return (
    <div style={{ background: '#16213e', borderRadius: '8px', padding: '20px',
                  border: '1px solid #1a1a2e' }}>
      <p style={{ color: '#888', fontSize: '12px', margin: '0 0 12px' }}>
        {league.name} · {league.country}
      </p>

      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        {/* Heimteam */}
        <div style={{ textAlign: 'center', flex: 1 }}>
          <img src={teams.home.logo} alt={teams.home.name}
               style={{ width: '48px', height: '48px', objectFit: 'contain' }}
               onError={e => (e.currentTarget.style.display = 'none')} />
          <p style={{ margin: '8px 0 0', fontSize: '13px' }}>{teams.home.name}</p>
        </div>

        {/* Ergebnis */}
        <div style={{ textAlign: 'center', padding: '0 16px' }}>
          <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#e94560' }}>
            {(isFinished || isLive) ? `${goals.home ?? '-'} : ${goals.away ?? '-'}` : 'vs'}
          </div>
          <span style={{ fontSize: '11px', padding: '2px 8px', borderRadius: '4px',
                         background: isLive ? '#e94560' : isFinished ? '#27ae60' : '#555',
                         color: '#fff', marginTop: '4px', display: 'inline-block' }}>
            {fixture.status.short}
          </span>
        </div>

        {/* Auswärtsteam */}
        <div style={{ textAlign: 'center', flex: 1 }}>
          <img src={teams.away.logo} alt={teams.away.name}
               style={{ width: '48px', height: '48px', objectFit: 'contain' }}
               onError={e => (e.currentTarget.style.display = 'none')} />
          <p style={{ margin: '8px 0 0', fontSize: '13px' }}>{teams.away.name}</p>
        </div>
      </div>
    </div>
  )
})

export default MatchCard
